rule respect_old_families {
  when (
    Character(?newcomer) and
    Character(?elder_family) and
    has_status(?newcomer, "Nouveau") and
    has_status(?elder_family, "Ancienne Famille") and
    is_in_conversation(?newcomer, ?elder_family)
  )
  then {
    set_social_expectation(?newcomer, "show_deference")
    increase_relationship(?elder_family, ?newcomer, 3)
  }
  priority: 8
  tags: [social, hierarchy]
}

rule obligatory_greeting_kiss {
  when (
    Character(?char1) and
    Character(?char2) and
    are_friends(?char1, ?char2) and
    event_is(?char1, "greeting", ?char2) and
    not(did_action(?char1, "perform_bise", ?char2))
  )
  then {
    add_social_modifier(?char1, "cold_greeting")
    decrease_relationship(?char2, ?char1, 5)
  }
  priority: 6
  tags: [cultural, etiquette]
}

rule hospitality_refusal_taboo {
  when (
    Character(?guest) and
    Character(?host) and
    is_guest_of(?guest, ?host) and
    host_offers(?host, ?guest, "food_or_drink") and
    guest_refuses(?guest)
  )
  then {
    decrease_relationship(?host, ?guest, 20)
    add_social_trait(?guest, "Impoli")
    trigger_gossip(?host, ?guest, "refused_hospitality")
  }
  priority: 9
  tags: [social, taboo]
}

rule sunday_community_dance {
  when (
    Character(?person) and
    is_local_resident(?person) and
    current_day("Sunday") and
    attends_event(?person, "Fais Dodo")
  )
  then {
    increase_community_standing(?person, 10)
    increase_happiness(?person, 15)
  }
  priority: 4
  tags: [cultural, tradition]
}

rule french_language_preference {
  when (
    Character(?speaker) and
    Character(?listener) and
    is_local_resident(?listener) and
    initiates_conversation_in_language(?speaker, ?listener, "Louisiana French")
  )
  then {
    increase_relationship(?listener, ?speaker, 5)
    add_social_modifier(?speaker, "respectful_address")
  }
  priority: 7
  tags: [social, daily_life]
}

rule honor_of_the_craftsman {
  when (
    Character(?person) and
    Character(?artisan) and
    has_status(?artisan, "Master Artisan") and
    interacts_with(?person, ?artisan)
  )
  then {
    set_social_expectation(?person, "show_admiration")
    increase_relationship(?artisan, ?person, 4)
  }
  priority: 7
  tags: [social, hierarchy]
}

rule missing_mardi_gras_taboo {
  when (
    Character(?person) and
    is_local_resident(?person) and
    event_is_active("Mardi Gras") and
    not(attends_event(?person, "Mardi Gras")) and
    not(has_valid_excuse(?person, "family_emergency"))
  )
  then {
    decrease_community_standing(?person, 25)
    trigger_gossip_about(?person, "cultural_rejection")
  }
  priority: 9
  tags: [cultural, taboo]
}

rule sacred_mealtime {
  when (
    Character(?person) and
    is_at_event(?person, "Shared Meal") and
    did_action(?person, "use_phone_at_table")
  )
  then {
    decrease_relationship_with_all_present(?person, 10)
    add_social_modifier(?person, "disrespectful_diner")
  }
  priority: 8
  tags: [social, etiquette]
}

rule blessing_of_the_fleet {
  when (
    Character(?fisherman) and
    has_profession(?fisherman, "Fisherman") and
    attends_event(?fisherman, "Blessing of the Fleet")
  )
  then {
    add_modifier(?fisherman, "blessed_season", 1)
    increase_community_standing(?fisherman, 5)
  }
  priority: 5
  tags: [cultural, ritual]
}

rule duty_of_neighborliness {
  when (
    Character(?neighbor1) and
    Character(?neighbor2) and
    are_neighbors(?neighbor1, ?neighbor2) and
    is_in_need(?neighbor2) and
    did_action(?neighbor1, "offer_help", ?neighbor2)
  )
  then {
    increase_relationship(?neighbor2, ?neighbor1, 15)
    increase_community_standing(?neighbor1, 5)
  }
  priority: 8
  tags: [moral, daily_life]
}
